"use strict";parserFactory.register("m.xklxsw.net",()=>new XklxswParser);class XklxswParser extends Parser{constructor(){super()}async getChapterUrls(r){let e=r.querySelector("#allChapters2");return util.hyperlinksToChapterList(e)}findContent(r){return r.querySelector("#nr")}extractTitleImpl(r){return r.querySelector(".cover h2 a")}findChapterTitle(r){return r.querySelector("#nr_title")}findCoverImageUrl(r){return util.getFirstImgSrc(r,".cover")}getInformationEpubItemChildNodes(r){return[...r.querySelectorAll(".intro_info")]}}